    #[must_use]
    pub fn toggle<T, C: Collection<T>>(&self, key: Key, collection: &C) -> Self {
        if self.is_selected(&key) {
            match &self.selected_keys {
                Set::All => self.deselect_from_all(&key, collection),

                _ => self.deselect(&key),
            }
        } else {
            self.select(key)
        }
    }

