    #[must_use]
    pub fn select_all(&self) -> Self {
        if self.mode != Mode::Multiple {
            return self.clone();
        }

        Self {
            selected_keys: Set::All,
            ..self.clone()
        }
    }

    /// Clears the selection.
    #[must_use]
    pub fn clear(&self) -> Self {
