+        if old.disabled != new.disabled
+            || old.dir != new.dir
+            || old.disabled_items != new.disabled_items
+            || old.selection_mode != new.selection_mode
+        {
+            vec![Event::SetProps]
+        } else {
+            Vec::new()
+        }
+    }
