+    fn item_tabindex(&self, id: &Key) -> &'static str {
+        if self.is_item_disabled(id) {
+            return "-1";
+        }
+
+        if self.is_roving_anchor(id) {
+            "0"
+        } else {
+            "-1"
+        }
+    }
