+
+    fn part_attrs(&self, part: Part) -> AttrMap {
+        match part {
+            Part::Root => self.root_attrs(),
+            Part::Item { ref item_id } => self.item_attrs(item_id),
+            Part::OverflowTrigger => self.overflow_trigger_attrs(),
+        }
+    }
