   383	                let first_for_state = first.clone();
   384	                Some(TransitionPlan::to(State::Focused {
   385	                    item: first_for_state.unwrap_or_default(),
   386	                }).apply(move |ctx| {
   387	                    ctx.focused_item = first;
   388	                }))
   389	            }
   390	
