   434	                            } else {
   435	                                ctx.selected_items.insert(id);
   436	                            }
   437	                        }))
   438	                    }
   439	                }
   440	            }
   441	
   442	            // ── OverflowChanged ─────────────────────────────────────────────
   443	            (_, Event::OverflowChanged(count)) => {
