   477	                Some(plan.apply(move |ctx| {
   478	                    ctx.registered_items.retain(|registered| registered != &id);
   479	                    ctx.selected_items.remove(&id);
   480	                    ctx.visible_count = ctx.registered_items.len().saturating_sub(ctx.overflow_count);
